const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const donations = JSON.parse(localStorage.getItem('donations') || '[]');

// Featured programs (shown on donate page)
const featuredPrograms = programs.filter(p => p && p.isFeaturedOnDonatePage === true);

// Find the featured program with the highest childrenFedPer10
let topProgram = null;
if (featuredPrograms.length > 0) {
  topProgram = featuredPrograms.reduce((best, p) => {
    const val = typeof p.childrenFedPer10 === 'number' ? p.childrenFedPer10 : -Infinity;
    const bestVal = best && typeof best.childrenFedPer10 === 'number' ? best.childrenFedPer10 : -Infinity;
    return val > bestVal ? p : best;
  }, null);
}

// One-time, program-restricted, card donations between $40 and $50 with fees covered to any featured program
const qualifyingAnyFeatured = donations.filter(d => {
  if (!d) return false;
  if (d.donationType !== 'program_restricted') return false;
  if (d.frequency !== 'one_time') return false;
  if (d.paymentMethodType !== 'credit_debit_card') return false;
  if (d.processingFeeCovered !== true) return false;
  const amt = Number(d.amount) || 0;
  if (amt < 40 || amt > 50) return false;
  const prog = featuredPrograms.find(p => p.id === d.programId);
  return !!prog;
});

// CP1 (0.4): Made at least one qualifying one-time card donation in the $40–$50 range with fees covered to ANY featured program
checkpoints.push({ passed: qualifyingAnyFeatured.length > 0, weight: 0.4 });

// Donations specifically to the top-impact featured program
let qualifyingToTop = [];
if (topProgram) {
  qualifyingToTop = qualifyingAnyFeatured.filter(d => d.programId === topProgram.id);
}

// CP2 (0.6): At least one such donation went to the featured program with the highest childrenFedPer10
checkpoints.push({ passed: !!topProgram && qualifyingToTop.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const countries = JSON.parse(localStorage.getItem('countries') || '[]');
const schedules = JSON.parse(localStorage.getItem('recurring_donation_schedules') || '[]');
const donations = JSON.parse(localStorage.getItem('donations') || '[]');

// Countries that can be targeted for donations
const donationTargetCountries = countries.filter(c => c && c.isDonationTarget === true && typeof c.childMalnutritionRatePercent === 'number');

// Country with highest child malnutrition rate
let topCountry = null;
if (donationTargetCountries.length > 0) {
  topCountry = donationTargetCountries.reduce((best, c) => {
    const val = c.childMalnutritionRatePercent;
    const bestVal = best ? best.childMalnutritionRatePercent : -Infinity;
    return val > bestVal ? c : best;
  }, null);
}

// Recurring schedules that match task criteria to ANY donation-target country
const baseQualifyingSchedules = schedules.filter(s => {
  if (!s) return false;
  if (s.donationType !== 'country_targeted') return false;
  if (s.frequency !== 'monthly') return false;
  if (s.paymentMethodType !== 'credit_debit_card') return false;
  if (s.smsOptIn !== true) return false;
  const amt = Number(s.amount) || 0;
  if (amt < 20 || amt > 30) return false;
  if (Number(s.chargeDayOfMonth) !== 15) return false; // mid-month as day 15
  const country = donationTargetCountries.find(c => c.id === s.countryId);
  return !!country;
});

// CP1 (0.4): At least one qualifying monthly card schedule (amount $20–$30, SMS opt-in, 15th) to ANY donation-target country
checkpoints.push({ passed: baseQualifyingSchedules.length > 0, weight: 0.4 });

// Among those, schedules specifically to the highest-malnutrition country
let toTopCountrySchedules = [];
if (topCountry) {
  toTopCountrySchedules = baseQualifyingSchedules.filter(s => s.countryId === topCountry.id);
}

// CP2 (0.4): At least one qualifying schedule targets the country with the highest child malnutrition rate
checkpoints.push({ passed: !!topCountry && toTopCountrySchedules.length > 0, weight: 0.4 });

// CP3 (0.2): A matching monthly donation record exists for one of those top-country schedules
let hasMatchingDonation = false;
if (toTopCountrySchedules.length > 0 && donations.length > 0) {
  hasMatchingDonation = toTopCountrySchedules.some(s => {
    return donations.some(d => {
      if (!d) return false;
      if (d.donationType !== s.donationType) return false;
      if (d.frequency !== 'monthly') return false;
      if (d.paymentMethodType !== s.paymentMethodType) return false;
      if (d.countryId !== s.countryId) return false;
      return Number(d.amount) === Number(s.amount);
    });
  });
}
checkpoints.push({ passed: hasMatchingDonation, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function geocodeZip(zip) {
  if (zip === '94103') return { lat: 37.773972, lng: -122.431297 };
  return null;
}
function toRad(v) { return (v * Math.PI) / 180; }
function haversineMiles(lat1, lng1, lat2, lng2) {
  const R = 3958.8;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
            Math.cos(toRad(lat1)) * Math.cos(lat2 * Math.PI / 180) *
            Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

const opps = JSON.parse(localStorage.getItem('volunteer_opportunities') || '[]');
const regs = JSON.parse(localStorage.getItem('volunteer_registrations') || '[]');

// Next month relative to scenario (April 2026)
const monthStart = new Date('2026-04-01T00:00:00Z');
const monthEnd = new Date('2026-04-30T23:59:59Z');
const center = geocodeZip('94103');

// All high-need Saturday meal-packing opps in April 2026 within 20 miles of 94103
const candidates = opps.filter(o => {
  if (!o) return false;
  if (o.activityType !== 'meal_packing') return false;
  if (o.needLevel !== 'high') return false;
  const start = new Date(o.startDateTime);
  if (start < monthStart || start > monthEnd) return false;
  // Saturday in UTC
  if (start.getUTCDay() !== 6) return false;
  if (!center || typeof o.latitude !== 'number' || typeof o.longitude !== 'number') return false;
  const dist = haversineMiles(center.lat, center.lng, o.latitude, o.longitude);
  return dist <= 20;
});

const candidateIds = candidates.map(o => o.id);

// Registrations for any qualifying candidate with exactly 1 adult and 0 youth
const regsForCandidates = regs.filter(r => {
  if (!r) return false;
  if (!candidateIds.includes(r.volunteerOpportunityId)) return false;
  const adults = Number(r.numAdultParticipants) || 0;
  const youth = Number(r.numYouthParticipants) || 0;
  return adults === 1 && youth === 0;
});

// CP1 (0.3): Registered one adult and no youth for ANY qualifying high-need Saturday meal-packing opp within 20 miles in that month
checkpoints.push({ passed: regsForCandidates.length > 0, weight: 0.3 });

// Find the earliest such opportunity by start date
let earliestOpp = null;
if (candidates.length > 0) {
  earliestOpp = candidates.slice().sort((a, b) => new Date(a.startDateTime) - new Date(b.startDateTime))[0];
}

// Registrations specifically for the earliest qualifying opportunity
let regsForEarliest = [];
if (earliestOpp) {
  regsForEarliest = regsForCandidates.filter(r => r.volunteerOpportunityId === earliestOpp.id);
}

// CP2 (0.7): That registration targets the earliest matching opportunity (one adult, no youth)
checkpoints.push({ passed: !!earliestOpp && regsForEarliest.length > 0, weight: 0.7 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const children = JSON.parse(localStorage.getItem('children') || '[]');
const commitments = JSON.parse(localStorage.getItem('sponsorship_commitments') || '[]');

// Children in Central America aged 6–10
const centralKids6to10 = children.filter(c => {
  if (!c) return false;
  if (c.regionCode !== 'central_america') return false;
  const age = Number(c.age) || 0;
  return age >= 6 && age <= 10;
});

// Longest-waiting child among those
let longestWaitingChild = null;
if (centralKids6to10.length > 0) {
  longestWaitingChild = centralKids6to10.reduce((best, c) => {
    const days = Number(c.daysWaiting) || 0;
    const bestDays = best ? (Number(best.daysWaiting) || 0) : -Infinity;
    return days > bestDays ? c : best;
  }, null);
}

// Sponsorships that are monthly and about $40 for any Central America child aged 6–10
const qualifyingCommitments = commitments.filter(s => {
  if (!s) return false;
  if (s.frequency !== 'monthly') return false;
  const amt = Number(s.amount) || 0;
  // "Around $40": allow a reasonable band, e.g., $35–$45
  if (amt < 35 || amt > 45) return false;
  const child = centralKids6to10.find(c => c.id === s.childId);
  return !!child;
});

// CP1 (0.4): Started a roughly $40/month sponsorship for some eligible 6–10 y/o child in Central America
checkpoints.push({ passed: qualifyingCommitments.length > 0, weight: 0.4 });

// Among those, sponsorships specifically for the longest-waiting eligible child
let commitsForLongest = [];
if (longestWaitingChild) {
  commitsForLongest = qualifyingCommitments.filter(s => s.childId === longestWaitingChild.id);
}

// CP2 (0.4): At least one such sponsorship is for the longest-waiting qualifying child
checkpoints.push({ passed: !!longestWaitingChild && commitsForLongest.length > 0, weight: 0.4 });

// CP3 (0.2): That longest-waiting child is now no longer marked as waiting AND has a sponsorship
let childNow = null;
if (longestWaitingChild) {
  childNow = children.find(c => c.id === longestWaitingChild.id) || null;
}
const childNoLongerWaiting = !!childNow && childNow.isWaitingForSponsorship === false && commitments.some(s => s.childId === longestWaitingChild.id);
checkpoints.push({ passed: childNoLongerWaiting, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('fundraising_events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');
const participants = JSON.parse(localStorage.getItem('event_participants') || '[]');

const juneStart = new Date('2026-06-01T00:00:00Z');
const juneEnd = new Date('2026-06-30T23:59:59Z');

// Family-friendly 5K run/walk events in Chicago in June of the scenario year
const family5kEvents = events.filter(e => {
  if (!e) return false;
  if (e.eventType !== 'run_walk') return false;
  if (e.city !== 'Chicago') return false;
  if (!e.isFamilyFriendly) return false;
  const d = new Date(e.eventDate);
  if (d < juneStart || d > juneEnd) return false;
  const text = ((e.title || '') + ' ' + (Array.isArray(e.keywords) ? e.keywords.join(' ') : '')).toLowerCase();
  return text.includes('family 5k');
});

// Earliest such event by date
let earliestEvent = null;
if (family5kEvents.length > 0) {
  earliestEvent = family5kEvents.slice().sort((a, b) => new Date(a.eventDate) - new Date(b.eventDate))[0];
}

function registrationHasAdultAndChild(reg) {
  const ps = participants.filter(p => p && p.eventRegistrationId === reg.id);
  const adultCount = ps.filter(p => p.participantType === 'adult').length;
  const childCount = ps.filter(p => p.participantType === 'child').length;
  return adultCount >= 1 && childCount >= 1;
}

// Registrations for ANY qualifying Chicago family 5K event choosing that event's earliest start time and including at least one adult and one child
const regsForAnyFamily5kEarliestTime = regs.filter(r => {
  if (!r) return false;
  const ev = family5kEvents.find(e => e.id === r.fundraisingEventId);
  if (!ev) return false;
  if (r.selectedStartTime !== ev.earliestStartTime) return false;
  return registrationHasAdultAndChild(r);
});

// CP1 (0.3): Registered at least one adult and one child for some Chicago June family 5K at that event’s earliest start time
checkpoints.push({ passed: regsForAnyFamily5kEarliestTime.length > 0, weight: 0.3 });

// Registrations specifically for the earliest such event, at its earliest start time
let regsForEarliestEvent = [];
if (earliestEvent) {
  regsForEarliestEvent = regs.filter(r => {
    if (!r) return false;
    if (r.fundraisingEventId !== earliestEvent.id) return false;
    if (r.selectedStartTime !== earliestEvent.earliestStartTime) return false;
    return registrationHasAdultAndChild(r);
  });
}

// CP2 (0.5): Such a registration exists for the earliest qualifying Chicago family 5K event, using that event’s earliest start time
checkpoints.push({ passed: !!earliestEvent && regsForEarliestEvent.length > 0, weight: 0.5 });

// CP3 (0.2): For at least one of those registrations, there is exactly one adult and one child, and totalParticipants matches
let cp3Passed = false;
for (const r of regsForEarliestEvent) {
  const ps = participants.filter(p => p && p.eventRegistrationId === r.id);
  const adultCount = ps.filter(p => p.participantType === 'adult').length;
  const childCount = ps.filter(p => p.participantType === 'child').length;
  const total = ps.length;
  if (adultCount === 1 && childCount === 1 && Number(r.totalParticipants) === total) {
    cp3Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const campaigns = JSON.parse(localStorage.getItem('fundraising_campaigns') || '[]');
const pages = JSON.parse(localStorage.getItem('personal_fundraising_pages') || '[]');

function wordCount(text) {
  return String(text || '').trim().split(/\s+/).filter(Boolean).length;
}

// Active peer-to-peer Summer Meals campaigns
const summerCampaigns = campaigns.filter(c => {
  if (!c) return false;
  if (c.status !== 'active') return false;
  if (c.campaignType !== 'peer_to_peer') return false;
  return (c.name || '').toLowerCase().includes('summer meals');
});

const summerCampaignIds = summerCampaigns.map(c => c.id);

// Personal pages for those campaigns that meet goal, title, URL, and story-length requirements
const qualifyingPages = pages.filter(p => {
  if (!p) return false;
  if (!summerCampaignIds.includes(p.campaignId)) return false;
  const goal = Number(p.goalAmount) || 0;
  if (goal < 400 || goal > 600) return false;
  if (typeof p.customUrlSlug !== 'string' || p.customUrlSlug.trim() === '') return false;
  if (typeof p.title !== 'string' || p.title.trim() === '') return false;
  if (wordCount(p.story) < 40) return false;
  if (p.status !== 'active') return false;
  return true;
});

// CP1 (0.6): Created at least one qualifying personal page in an active Summer Meals peer-to-peer campaign
checkpoints.push({ passed: qualifyingPages.length > 0, weight: 0.6 });

// Among qualifying pages, check that the share link was copied at least once
const linkCopiedForAny = qualifyingPages.some(p => !!p.lastLinkCopiedAt);

// CP2 (0.4): Used the on-site control to copy the shareable link for a qualifying page
checkpoints.push({ passed: linkCopiedForAny, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const requests = JSON.parse(localStorage.getItem('info_kit_requests') || '[]');

// Eligible African school meal programs serving at least 50,000 children
const eligiblePrograms = programs.filter(p => {
  if (!p) return false;
  if (p.regionCode !== 'africa') return false;
  if (p.programType !== 'school_meal_program') return false;
  const total = Number(p.childrenServedTotal) || 0;
  return total >= 50000;
});

const eligibleProgramIds = eligiblePrograms.map(p => p.id);

// Info kit requests matching criteria
const qualifyingRequests = requests.filter(r => {
  if (!r) return false;
  if (!eligibleProgramIds.includes(r.programId)) return false;
  // Delivery method representing postal + email
  if (r.deliveryMethod !== 'postal_mail_plus_email') return false;
  // Required contact fields should all be present
  if (!r.fullName || !r.email || !r.addressLine1 || !r.city || !r.state || !r.postalCode || !r.country) return false;
  return true;
});

// CP1 (1.0): Submitted at least one info kit request meeting all program, delivery method, and contact-field requirements
checkpoints.push({ passed: qualifyingRequests.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const topics = JSON.parse(localStorage.getItem('advocacy_topics') || '[]');
const reps = JSON.parse(localStorage.getItem('representatives') || '[]');
const letters = JSON.parse(localStorage.getItem('advocacy_letters') || '[]');

function wordCount(text) {
  return String(text || '').trim().split(/\s+/).filter(Boolean).length;
}

// Topic for increasing school breakfast funding
const topic = topics.find(t => t && (t.topicCode === 'increase_school_breakfast_funding' || t.id === 'increase_school_breakfast_funding')) || null;

// Representatives for ZIP 10001 (same logic as BusinessLogic._lookupRepresentativesForZip)
const repsForZip = reps.filter(r => {
  if (!r) return false;
  if (Array.isArray(r.supportedZipCodes) && r.supportedZipCodes.includes('10001')) return true;
  if (r.postalCode === '10001') return true;
  return false;
});

const expectedRepIds = Array.from(new Set(repsForZip.map(r => r.id)));

// Letters that meet all criteria
const qualifyingLetters = letters.filter(l => {
  if (!l) return false;
  if (!topic || l.topicId !== topic.id) return false;
  if (l.zipCode !== '10001') return false;
  if (!l.sendEmailThroughSite) return false;
  if (!l.generatePrintReadyPdf) return false;
  if (!Array.isArray(l.recipientIds)) return false;
  // custom text words >= 20
  if (wordCount(l.customTextAdded) < 20) return false;
  // Recipients must exactly match all representatives for ZIP 10001 (order-insensitive, no extras)
  const letterRecipientIds = Array.from(new Set(l.recipientIds));
  if (expectedRepIds.length === 0) return false;
  if (letterRecipientIds.length !== expectedRepIds.length) return false;
  const allPresent = expectedRepIds.every(id => letterRecipientIds.includes(id));
  if (!allPresent) return false;
  return true;
});

// CP1 (1.0): Sent at least one advocacy letter meeting all topic, ZIP, recipient, custom-text, and delivery-option requirements
checkpoints.push({ passed: qualifyingLetters.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
